		logger        = zaptest.NewLogger(t)
		store         = newTestAuthStore(t)
		listener      = bufconn.Listen(1024 * 1024)
		interceptors  = []grpc.UnaryServerInterceptor{
			middleware.ErrorUnaryInterceptor,
			middleware.ValidationUnaryInterceptor,
			auth_pkg.UnaryInterceptor(logger, store),
		}
		server = grpc.NewServer(
			grpc_middleware.WithUnaryServerChain(interceptors...),
		)
		errC = make(chan error, 1)
	)

	defer server.Stop()

	// Register the auth service
	authServer := auth_pkg.NewServer(logger, store)
	authrpc.RegisterAuthenticationServiceServer(server, authServer)

	go func() {
		errC <- server.Serve(listener)
	}()
	defer func() {
		server.Stop()
		if err := <-errC; err != nil && err != grpc.ErrServerStopped {
			t.Logf("server error: %v", err)
		}
	}()

	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	// Create a valid client token
	clientToken, authentication, err := store.CreateAuthentication(ctx, &auth.CreateAuthenticationRequest{
		Method: authrpc.Method_METHOD_TOKEN,
	})
	require.NoError(t, err)
	require.NotEmpty(t, clientToken)
	require.NotNil(t, authentication)

	// Set up client connection
	dialer := func(context.Context, string) (net.Conn, error) {
		return listener.Dial()
	}

	conn, err := grpc.DialContext(ctx, "", grpc.WithInsecure(), grpc.WithContextDialer(dialer))
	require.NoError(t, err)
	defer conn.Close()

	client := authrpc.NewAuthenticationServiceClient(conn)

	// Test 1: Using valid token via Authorization header (Bearer) - SHOULD SUCCEED
	t.Run("BearerTokenSucceeds", func(t *testing.T) {
		mdCtx := metadata.AppendToOutgoingContext(ctx, "authorization", "Bearer "+clientToken)
		resp, err := client.GetAuthenticationSelf(mdCtx, &emptypb.Empty{})
		assert.NoError(t, err, "authentication with Bearer token should succeed")
		assert.NotNil(t, resp)
		assert.Equal(t, authentication.Id, resp.Id)
	})

